UPDATE ticket_search_event
SET event_status = #{targetStatus}, claimed_at = NOW(), update_time = NOW()
WHERE event_id = #{eventId} AND event_status = #{expectedStatus}

UPDATE ticket_search_event
SET event_status = 'SUCCEEDED', processed_at = NOW(), error_message = NULL, update_time = NOW()
WHERE event_id = #{eventId} AND event_status = #{expectedStatus}

UPDATE ticket_search_event
SET event_status = #{pendingStatus}, claimed_at = NULL, next_retry_at = NOW(), update_time = NOW()
WHERE event_status = #{processingStatus} AND claimed_at < #{claimedBefore}
